    if ($item && $item->is_recurring == 1) {
        $event_remaining = false;
        $eventdates = $item->eventdate[0]->find('all', 'event_id=' . $item->id);
        foreach ($eventdates as $ed) {
            if (array_key_exists($ed->id, $this->params['dates'])) {
                $ed->delete();
            } else {
                $event_remaining = true;
            }
        }
        if (!$event_remaining) {
