    if (!empty($this->config['pull_rss'])) $items = $this->mergeRssData($items);

    // setup the pagination object to paginate the news stories.
    $page = new expPaginator(array(
        'records'=>$items,
        'limit'=>$limit,
        'order'=>$order,
